// kilodash polls this ~every 2s. Values/labels come from FLOW CONTEXT so any
// other node can feed a field just by writing flow.f1 .. flow.f6 (and, if you
// want a custom name, flow.f1_label .. flow.f6_label). Same for button labels
// (flow.b1_label .. flow.b6_label).
const label = (k, d) => flow.get(k) ?? d;
const value = (k) => { const v = flow.get(k); return (v === undefined || v === null) ? '\u2014' : v; };
const N = 6;
msg.payload = {
    fields: Array.from({length: N}, (_, i) => ({
        label: label(`f${i + 1}_label`, `Field ${i + 1}`),
        value: value(`f${i + 1}`)
    })),
    buttons: Array.from({length: N}, (_, i) => ({
        label: label(`b${i + 1}_label`, `Trigger ${i + 1}`)
    }))
};
return msg;

// Fired when a kilodash panel button is tapped. msg.req.params.n is '1'..'6'.
const n = msg.req.params.n;
node.warn('kilodash trigger ' + n);
// TODO: branch on n and do your action, e.g.:
//   if (n === '1') { /* toggle a GPIO, send MQTT, etc. */ }
msg.payload = { ok: true, btn: n };
return msg;

// Example: label Field 1 'Clock' and feed it a live value.
flow.set('f1_label', 'Clock');
flow.set('f1', new Date().toLocaleTimeString());
return null;
